mapper.select:
SELECT tabulation_id
FROM t_car_cost_tabulation
WHERE module_id = #{moduleId} AND module_type = #{moduleType}

SELECT *
FROM t_car_cost_tabulation
WHERE module_id = #{moduleId} AND module_type = #{moduleType}

SELECT *
FROM t_car_cost_tabulation
where enterprise_id = #{enterpriseId}
ORDER BY create_time DESC
LIMIT #{limitNum}

SELECT cct.tabulation_id,
       cct.module_type
FROM t_car_cost_tabulation cct
LEFT JOIN t_waybill w ON cct.waybill_id = w.waybill_id
LEFT JOIN t_car_cost_category ccc ON cct.category_id = ccc.category_id


        AND cct.enterprise_id = #{queryForm.enterpriseId}


        AND cct.audit_status = #{queryForm.auditStatus}


        AND cct.driver_id = #{queryForm.driverId}


        AND cct.vehicle_id = #{queryForm.vehicleId}


        AND ccc.cost_type = #{queryForm.costType}


        AND cct.category_id = #{queryForm.categoryId}


        AND INSTR(w.waybill_number, #{queryForm.waybillNumber})


        AND INSTR(w.container_number, #{queryForm.containerNumber})


ORDER BY cct.create_time DESC,cct.tabulation_id DESC

SELECT *
FROM t_car_cost_tabulation
where waybill_id = #{waybillId} AND audit_status = #{auditStatus}

SELECT COUNT(1)
FROM t_car_cost_tabulation
WHERE waybill_id = #{waybillId} AND audit_status = #{auditStatus}

SELECT cct.*, ccc.cost_type, ccc.category_name, ccc.pay_mode FROM t_car_cost_tabulation cct LEFT JOIN t_car_cost_category ccc ON cct.category_id = ccc.category_id WHERE cct.waybill_id IN
#{id}
AND cct.module_type IN
#{type}
AND cct.audit_status = #{auditStatus}
